import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

// Simulating a complete JWT + refresh token auth system
class AuthSystem {
    // In production: these would be DB tables + Redis
    private final Map<String, String> users = Map.of(
        "alice", "$2a$10$hashedpassword"); // BCrypt hashes
    private final Map<String, RefreshToken> refreshTokens = new ConcurrentHashMap<>();
    private final Set<String> revokedTokens = ConcurrentHashMap.newKeySet();

    record RefreshToken(String userId, String token, long expiresAt, boolean used) {
        boolean isExpired() { return System.currentTimeMillis() > expiresAt; }
    }

    // Simulate JwtService
    String generateAccessToken(String userId) {
        // In real: signed JWT with 15min expiry
        return "access_" + userId + "_" + System.currentTimeMillis();
    }
    String extractUserId(String accessToken) {
        return accessToken.split("_")[1]; // simplification
    }
    boolean isAccessTokenValid(String token) {
        return token.startsWith("access_") && !revokedTokens.contains(token);
    }

    // LOGIN: returns access + refresh token
    Map<String, String> login(String username) {
        String refreshToken = UUID.randomUUID().toString();
        refreshTokens.put(refreshToken, new RefreshToken(
            username, refreshToken,
            System.currentTimeMillis() + 7 * 24 * 60 * 60 * 1000L, // 7 days
            false));
        return Map.of(
            "accessToken",  generateAccessToken(username),
            "refreshToken", refreshToken  // sent as httpOnly cookie in real app
        );
    }

    // REFRESH: rotate refresh token
    Map<String, String> refresh(String oldRefreshToken) {
        RefreshToken rt = refreshTokens.get(oldRefreshToken);
        if (rt == null)      throw new RuntimeException("Invalid refresh token");
        if (rt.isExpired())  throw new RuntimeException("Refresh token expired");
        if (rt.used())  {
            // Token reuse detected — possible token theft — revoke all for this user
            revokeAllForUser(rt.userId());
            throw new RuntimeException("Refresh token reuse detected — all sessions revoked");
        }

        // Mark old token as used
        refreshTokens.put(oldRefreshToken, new RefreshToken(
            rt.userId(), oldRefreshToken, rt.expiresAt(), true));

        // Issue new tokens (rotation)
        return login(rt.userId());
    }

    void revokeAllForUser(String userId) {
        refreshTokens.values().removeIf(rt -> rt.userId().equals(userId));
        System.out.println("[SECURITY] All sessions revoked for " + userId);
    }

    // LOGOUT
    void logout(String refreshToken) {
        refreshTokens.remove(refreshToken);
    }
}

public class AuthFlowDemo {
    public static void main(String[] args) throws InterruptedException {
        AuthSystem auth = new AuthSystem();

        System.out.println("=== Login ===");
        var tokens = auth.login("alice");
        System.out.println("Access:  " + tokens.get("accessToken"));
        System.out.println("Refresh: " + tokens.get("refreshToken"));

        System.out.println("\n=== Refresh ===");
        var newTokens = auth.refresh(tokens.get("refreshToken"));
        System.out.println("New Access: " + newTokens.get("accessToken"));

        System.out.println("\n=== Reuse Detection ===");
        try {
            auth.refresh(tokens.get("refreshToken")); // old token reused!
        } catch (RuntimeException e) {
            System.out.println("Caught: " + e.getMessage());
        }

        System.out.println("\n=== Logout ===");
        auth.logout(newTokens.get("refreshToken"));
        System.out.println("Logged out successfully");
    }
}

// OAuth2 Authorization Code Flow — sequence diagram as code comments
// Actors: User, Client (your app), Authorization Server (Google), Resource Server (your API)

public class OAuth2Flow {

    /*
     * STEP 1 — Client redirects user to Authorization Server:
     * GET https://accounts.google.com/o/oauth2/auth
     *   ?client_id=YOUR_CLIENT_ID
     *   &redirect_uri=https://yourapp.com/callback
     *   &response_type=code
     *   &scope=openid email profile
     *   &state=random_csrf_token       ← prevent CSRF
     *   &code_challenge=BASE64(SHA256(verifier))  ← PKCE
     *   &code_challenge_method=S256
     *
     * STEP 2 — User authenticates with Google, grants permissions
     *
     * STEP 3 — Google redirects back:
     * GET https://yourapp.com/callback
     *   ?code=AUTH_CODE_FROM_GOOGLE
     *   &state=random_csrf_token
     *
     * STEP 4 — Client exchanges code for tokens (server-side, secret never in browser):
     * POST https://oauth2.googleapis.com/token
     *   client_id, client_secret, code, redirect_uri,
     *   code_verifier (PKCE — proves same client that initiated)
     *   → { access_token, id_token (JWT with user info), refresh_token }
     *
     * STEP 5 — Client uses id_token to create/login user:
     *   - Decode id_token JWT (verify signature with Google's public key)
     *   - Extract email, name, sub (Google user ID)
     *   - Find or create user in your DB
     *   - Issue your own JWT to the user
     *
     * STEP 6 — Subsequent requests use YOUR JWT, not Google's token
     */

    // Simulated OAuth2 success handler (what Spring Security OAuth2 calls after step 4)
    static String handleOAuth2Success(String email, String name, String googleId) {
        System.out.println("OAuth2 login: " + name + " (" + email + ")");
        // Find or create user
        String userId = "user_" + googleId.hashCode();
        // Issue your own JWT
        String yourJwt = "jwt_" + userId + "_issued";
        System.out.println("Issued JWT: " + yourJwt);
        return yourJwt;
    }

    public static void main(String[] args) {
        // Simulating the callback handler after Google redirects back
        String jwt = handleOAuth2Success(
            "alice@gmail.com", "Alice", "google_sub_1234567");
        System.out.println("User gets: " + jwt);

        // Key differences from password auth:
        // 1. You never see the user's Google password
        // 2. Google handles MFA, account recovery
        // 3. state parameter prevents CSRF
        // 4. PKCE prevents authorization code interception
        System.out.println("\nOAuth2 vs Password:");
        System.out.println("Password: you store+verify credentials (responsibility + liability)");
        System.out.println("OAuth2:   Google/GitHub stores credentials, you trust their assertion");
    }
}

problems.description:
Design and implement JWT-based stateless authentication.

**JWT Structure:** header.payload.signature
```java
// Issue JWT on login:
public String generateToken(UserDetails user) {
    return Jwts.builder()
        .setSubject(user.getUsername())
        .claim("roles", user.getAuthorities())
        .setIssuedAt(new Date())
        .setExpiration(new Date(System.currentTimeMillis() + 86400000)) // 24h
        .signWith(secretKey, SignatureAlgorithm.HS256)
        .compact();
}

// Validate JWT:
public boolean isValid(String token, UserDetails user) {
    return extractUsername(token).equals(user.getUsername())
        && !isExpired(token);
}
```

**Key insight:** JWT is stateless — no DB lookup per request. Payload is readable (base64, not encrypted). Only the signature is secret. Use short expiry (15min-1hr) + refresh tokens for security.

