import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public class Q2 {
    static final Map<String, String> SESSION_STORE = new ConcurrentHashMap<>();

    static boolean validateSession(String sessionId) {
        return SESSION_STORE.containsKey(sessionId);
    }

    static boolean validateJwt(String token) {
        // Simulate HMAC computation (simplified)
        String[] parts = token.split("\\.");
        return parts.length == 3 && parts[2].equals(Integer.toHexString(parts[1].hashCode()));
    }

    public static void main(String[] args) {
        int N = 10_000;
        for (int i = 0; i < N; i++) SESSION_STORE.put("sess_" + i, "user_" + i);

        long t1 = System.nanoTime();
        for (int i = 0; i < N; i++) validateSession("sess_" + i);
        long sessionMs = (System.nanoTime() - t1) / 1_000_000;

        long t2 = System.nanoTime();
        for (int i = 0; i < N; i++) {
            String payload = "user_" + i;
            String sig = Integer.toHexString(payload.hashCode());
            validateJwt("header." + payload + "." + sig);
        }
        long jwtMs = (System.nanoTime() - t2) / 1_000_000;

        System.out.println("Session (local map): " + sessionMs + "ms");
        System.out.println("JWT (computation):   " + jwtMs + "ms");
        System.out.println("\nScalability:");
        System.out.println("Session: requires Redis (shared), 0.1-1ms network latency per request");
        System.out.println("JWT: local computation, no network, stateless horizontal scaling");
    }
}

