public class Q3 {
    public static void main(String[] args) {
        System.out.println("SSO Flow (OIDC/OAuth2-based):");
        System.out.println();
        System.out.println("1. User visits HR Portal → HR Portal checks: no local session");
        System.out.println("   → redirects to IdP: GET https://sso.company.com/auth?client_id=hr-portal");
        System.out.println();
        System.out.println("2. IdP checks: does user have an IdP session?");
        System.out.println("   → NO: show login form, user enters credentials");
        System.out.println("   → YES (already logged in): skip to step 3 immediately");
        System.out.println();
        System.out.println("3. IdP issues authorization code → redirects back to HR Portal");
        System.out.println("   HR Portal exchanges code for id_token + access_token (server-side)");
        System.out.println("   HR Portal verifies id_token signature with IdP's public key");
        System.out.println("   HR Portal creates local session for user");
        System.out.println();
        System.out.println("4. User visits Engineering Dashboard → no local session");
        System.out.println("   → redirects to IdP → IdP has session → auto-issues code → back");
        System.out.println("   → user never sees login form again (SSO magic)");
        System.out.println();
        System.out.println("5. Logout:");
        System.out.println("   → User logs out of HR Portal");
        System.out.println("   → HR Portal calls IdP /logout (central logout)");
        System.out.println("   → IdP sends back-channel logout to all registered SPs");
        System.out.println("   → Each SP invalidates its local session");
        System.out.println("   → User must re-authenticate at any SP next visit");
    }
}
